settings.dashboardCss:
/* ==========================================================================
   1. General Widget Styling
   ========================================================================== */

.tb-widget-container > .tb-widget {
  border-radius: 8px !important;
}

gridster-item:not(.tb-noselect) > .tb-widget-container > .tb-widget {
  cursor: default !important;
}

.tb-widget-container > .tb-widget .tb-table-widget .mat-mdc-row {
  cursor: pointer;
  --tb-orig-background-color: transparent;
}

.tb-widget-container > .tb-widget .tb-legend-keys {
  cursor: pointer;
}

/* ==========================================================================
   2. Dark Mode - Dashboard & Base Widget Colors
   ========================================================================== */

/* เปิด dark mode ที่ระดับ dashboard */
.tb-dashboard-page.dark {
  background: #0b1020;
  color: #e5e5e5;
}

.tb-dashboard-page.dark tb-dashboard > div {
  background-color: #0A1F36 !important; /* rgb(238, 238, 238) */
}

.tb-dashboard-page.dark .tb-widget-container > .tb-widget {
  background: #0D2743 !important;
  color: rgba(255, 255, 255, 0.87) !important;
}

/* ==========================================================================
   3. Dark Mode - Charts & Legends (อัปเดตสมบูรณ์)
   ========================================================================== */

/* 1. จัดการพื้นหลังของตัว Widget Chart ให้กลืนกับหน้าจอ */
.tb-dashboard-page.dark .tb-latest-chart-panel,
.tb-dashboard-page.dark .tb-widget-header {
  background-color: transparent !important; /* ให้ใช้สีพื้นหลังของตัว Container แม่ */
}

/* 2. เปลี่ยนสีข้อความในส่วน Header (เช่น ชื่อกราฟ) */
.tb-dashboard-page.dark .tb-widget-title-row,
.tb-dashboard-page.dark .tb-widget-title-row * {
  color: rgba(255, 255, 255, 0.87) !important;
}

/* 3. จัดการสีข้อความในส่วนของ Legend (คำอธิบายด้านข้าง/ด้านล่างกราฟ) ตามรูปที่แคปมา */
.tb-dashboard-page.dark .tb-latest-chart-legend-item,
.tb-dashboard-page.dark .tb-latest-chart-legend-item-label,
.tb-dashboard-page.dark .tb-latest-chart-legend-item-label *,
.tb-dashboard-page.dark .tb-latest-chart-legend-item-value {
  color: rgba(255, 255, 255, 0.87) !important;
}

/* เผื่อสำหรับกราฟเส้น (Time Series) ที่ใช้คลาส Legend อีกแบบ */
.tb-dashboard-page.dark .tb-time-series-chart-legend-item-label *,
.tb-dashboard-page.dark .tb-time-series-chart-legend-value {
  color: rgba(255, 255, 255, 0.87) !important;
}

/* 4. จัดการสีตัวหนังสือที่อยู่ในตัวกราฟ (SVG แกน X, Y หรือตัวเลขตรงกลาง Donut) */
.tb-dashboard-page.dark .tb-latest-chart-panel svg text,
.tb-dashboard-page.dark .tb-latest-chart-panel svg tspan,
.tb-dashboard-page.dark .flot-text,
.tb-dashboard-page.dark .flot-text * {
  fill: rgba(255, 255, 255, 0.87) !important;
  color: rgba(255, 255, 255, 0.87) !important;
}
/* ==========================================================================
   4. Dark Mode - Tables (อัปเดตแบบทะลวง Material CSS)
   ========================================================================== */

/* 1. ดึงพื้นหลังของตาราง ส่วนหัว และแถบเปลี่ยนหน้า(Paginator) ให้โปร่งใส */
.tb-dashboard-page.dark .tb-widget-container > .tb-widget .tb-table-widget,
.tb-dashboard-page.dark .tb-table-widget .mat-mdc-table,
.tb-dashboard-page.dark .tb-table-widget .mat-mdc-header-row,
.tb-dashboard-page.dark .tb-table-widget .mat-mdc-row,
.tb-dashboard-page.dark .tb-table-widget .mat-mdc-header-cell,
.tb-dashboard-page.dark .tb-table-widget .mat-mdc-cell,
.tb-dashboard-page.dark .tb-table-widget .mat-mdc-paginator {
  background-color: transparent !important;
}

/* 2. บังคับเปลี่ยนสีตัวหนังสือทุกจุดในตารางและ Paginator */
.tb-dashboard-page.dark .tb-table-widget .mat-mdc-table *,
.tb-dashboard-page.dark .tb-table-widget .mat-mdc-paginator * {
  color: rgba(255, 255, 255, 0.87) !important;
}

/* 3. สีเส้นขอบ (Borders) กั้นระหว่างแถวให้ดูจางๆ ไม่รบกวนสายตา */
.tb-dashboard-page.dark .tb-table-widget .mat-mdc-header-cell,
.tb-dashboard-page.dark .tb-table-widget .mat-mdc-cell,
.tb-dashboard-page.dark .tb-table-widget .mat-divider {
  border-bottom-color: rgba(255, 255, 255, 0.2) !important;
  border-top-color: rgba(255, 255, 255, 0.2) !important;
}

/* 4. ช่องค้นหา (Search) และ Placeholder */
.tb-dashboard-page.dark .tb-table-widget .mat-mdc-input-element {
  color: rgba(255, 255, 255, 0.87) !important;
}
.tb-dashboard-page.dark .tb-table-widget .mat-mdc-input-element::placeholder {
  color: rgba(255, 255, 255, 0.5) !important;
}

/* 5. ไอคอนปุ่มที่ถูก Disable (เช่น ปุ่มย้อนกลับหน้าแรกสุด) ให้สีดรอปลง */
.tb-dashboard-page.dark .tb-table-widget .mat-mdc-icon-button[disabled] * {
  color: rgba(255, 255, 255, 0.3) !important; 
}

/* ==========================================================================
   5. Dark Mode - Form Fields & Selects
   ========================================================================== */

.tb-dashboard-page.dark .tb-widget-container > .tb-widget .mat-mdc-select-arrow {
  color: rgba(255, 255, 255, 0.57);
}

.tb-dashboard-page.dark .tb-widget-container > .tb-widget .mdc-text-field--filled:not(.mdc-text-field--disabled) .mdc-line-ripple:before {
  border-bottom-color: rgba(255, 255, 255, 0.4);
}

.tb-dashboard-page.dark .tb-widget-container > .tb-widget .mdc-text-field--outlined:not(.mdc-text-field--disabled) .mdc-notched-outline__leading, 
.tb-dashboard-page.dark .tb-widget-container > .tb-widget .mdc-text-field--outlined:not(.mdc-text-field--disabled) .mdc-notched-outline__notch,
.tb-dashboard-page.dark .tb-widget-container > .tb-widget .mdc-text-field--outlined:not(.mdc-text-field--disabled) .mdc-notched-outline__trailing {
  border-color: rgba(255, 255, 255, 0.4);
}

/* ==========================================================================
   6. Dark Mode - Markdown View & Footer
   ========================================================================== */

.tb-dashboard-page.dark .tb-markdown-view div,
.tb-dashboard-page.dark .tb-markdown-view div.param,
.tb-dashboard-page.dark .tb-markdown-view .header .title,
.tb-dashboard-page.dark .tb-markdown-view p,
.tb-dashboard-page.dark .tb-powered-by-footer {
  color: rgba(255, 255, 255, 0.87) !important;
}

.tb-dashboard-page.dark .tb-markdown-view div.param-title,
.tb-dashboard-page.dark .tb-markdown-view .header .subtitle {
  color: rgba(255, 255, 255, 0.6);
}

/* ==========================================================================
   7. Dark Mode - Fullscreen & Specific Widgets (Map)
   ========================================================================== */

/* ตอน fullscreen */
.tb-dashboard-page.dark .tb-fullscreen .tb-widget-container,
.tb-dashboard-page.dark .tb-fullscreen .tb-widget {
  background-color: #0D2743 !important;
}

/* widget map ตามที่บอกว่ามี class widget-type-system-map และส่วนประกอบด้านใน */
.tb-dashboard-page.dark .tb-widget.widget-type-system-map,
.tb-dashboard-page.dark .tb-widget.widget-type-system-map .tb-absolute-fill.flex.flex-col,
.tb-dashboard-page.dark .tb-widget.widget-type-system-map .tb-map-widget,
.tb-dashboard-page.dark .tb-widget.widget-type-system-map .tb-map-panel {
  background-color: #0D2743 !important;
  color: rgba(255, 255, 255, 0.87) !important;
}

/* ==========================================================================
   8. Dark Mode - Value Cards
   ========================================================================== */

/* 1. จัดการพื้นหลังและกรอบของการ์ด */
.tb-dashboard-page.dark .tb-value-card-panel.square {
  background-color: #0D2743 !important;
  border-radius: 8px !important;
  border: 1px solid #29324a !important;
  box-shadow: 0 4px 10px rgba(0,0,0,0.5) !important;
}

/* 2. ทำให้พื้นหลังด้านในโปร่งใส เพื่อไม่ให้สีตีกัน */
.tb-dashboard-page.dark .tb-absolute-fill.flex.flex-col,
.tb-dashboard-page.dark .tb-value-card-content.square,
.tb-dashboard-page.dark .tb-value-card-icon-row,
.tb-dashboard-page.dark .tb-value-card-label-row {
  background: transparent !important;
}

/* 3. คำสั่งไม้ตาย: บังคับเปลี่ยนสีตัวหนังสือ "ทุกชั้น" ที่อยู่ในการ์ดให้เป็นสีเดียวกันหมด */
.tb-dashboard-page.dark .tb-value-card-panel.square,
.tb-dashboard-page.dark .tb-value-card-panel.square * {
  color: rgba(255, 255, 255, 0.87) !important;
}

/* เผื่อกรณีไอคอนเป็น SVG แล้วสีไม่เปลี่ยน */
.tb-dashboard-page.dark .tb-value-card-panel.square mat-icon,
.tb-dashboard-page.dark .tb-value-card-panel.square svg {
  fill: rgba(255, 255, 255, 0.87) !important;
}

/* ==========================================================================
   9. Dark Mode - Time Series Charts (อัปเดตจากรูป Inspect)
   ========================================================================== */

/* 1. พื้นหลังของ Time Series Chart ให้โปร่งใสกลืนกับ Widget */
.tb-dashboard-page.dark .tb-time-series-chart-panel,
.tb-dashboard-page.dark .tb-time-series-chart-content {
  background-color: transparent !important;
}

/* 2. สีตัวหนังสือของ Header, Title Row, ไอคอน และ Timewindow (ตัวเลือกเวลา) */
.tb-dashboard-page.dark .tb-time-series-chart-panel .title-row *,
.tb-dashboard-page.dark .tb-time-series-chart-panel .tb-timewindow *,
.tb-dashboard-page.dark .tb-time-series-chart-panel .tb-widget-actions * {
  color: rgba(255, 255, 255, 0.87) !important;
}

/* 3. สีตัวหนังสือในแกนกราฟ X, Y (SVG Text) */
.tb-dashboard-page.dark .tb-time-series-chart-shape svg text,
.tb-dashboard-page.dark .tb-time-series-chart-shape svg tspan {
  fill: rgba(255, 255, 255, 0.87) !important;
  color: rgba(255, 255, 255, 0.87) !important;
}
